INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26315baf-61aa-4fda-b2de-4986fe3babe9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$PostgreSQL wire compatibility$q$, $q$Connect using standard PostgreSQL drivers, ORMs, and tools, easing migration for existing Postgres applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Automatic sharding and rebalancing$q$, $q$Data is automatically distributed and rebalanced across nodes without manual partitioning.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Multi-region survivability$q$, $q$Raft-based replication allows the cluster to keep serving reads and writes through node or regional outages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Geo-partitioning$q$, $q$Pin specific rows of data to specific geographic regions for data residency and latency compliance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$ACID transactions at scale$q$, $q$Full relational transaction guarantees combined with horizontal, distributed scalability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Serverless Basic tier$q$, $q$Pay-as-you-go pricing that scales to zero when idle, ideal for bursty or unpredictable workloads.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$AI/agent tooling$q$, $q$MCP server, ccloud CLI, agent skills, and distributed vector indexing for AI and RAG-oriented workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Compliance certifications$q$, $q$Advanced tier supports CMEK encryption and HIPAA/PCI-DSS compliance requirements for regulated industries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Combines full ACID SQL transactions with true horizontal, multi-region scalability$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$PostgreSQL wire compatibility simplifies migration from existing Postgres applications$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Free self-hosted use for companies under $10M annual revenue under the current licensing model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Serverless Basic cloud tier offers a genuinely free entry point with no credit card commitment for small workloads$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Source-available license (not OSI-approved open source) requires payment for self-hosted use above the $10M revenue threshold$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Distributed architecture adds operational complexity and latency considerations compared to single-node databases for small workloads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Standard cloud tier was still in preview as of recent releases, indicating some product maturity gaps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Provisioned compute pricing (Standard/Advanced) can be more expensive than simpler managed Postgres offerings for steady, low-scale workloads$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Is CockroachDB free to use?$q$, $q$CockroachDB Cloud's Basic tier is free to start, including 50 million request units and 10 GiB of storage per month. Self-hosted CockroachDB is also free for companies with less than $10 million in annual revenue; larger companies pay a per-CPU-core fee under the current licensing model introduced in August 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Is CockroachDB open source?$q$, $q$CockroachDB is source-available rather than strictly open source under OSI definitions. The source code is publicly viewable, but commercial self-hosted use by companies above $10 million in annual revenue requires a paid license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Is CockroachDB compatible with PostgreSQL?$q$, $q$Yes, CockroachDB is wire-compatible with PostgreSQL, so applications can generally connect using standard PostgreSQL drivers, ORMs, and tools with minimal changes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Who founded Cockroach Labs?$q$, $q$Cockroach Labs was founded in 2015 by Spencer Kimball, Peter Mattis, and Ben Darnell, all former Google engineers who previously worked on Google's Spanner distributed database.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$What is the difference between CockroachDB Basic, Standard, and Advanced?$q$, $q$Basic is a pay-as-you-go serverless tier that scales to zero, suited for bursty workloads. Standard offers provisioned compute for steady workloads at scale. Advanced adds unlimited scaling, multi-region support across AWS/GCP/Azure, up to 99.999% uptime, and compliance features like CMEK and HIPAA/PCI-DSS support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$How does CockroachDB survive data center outages?$q$, $q$CockroachDB uses the Raft consensus protocol to replicate data across multiple nodes and regions, enabling multi-active availability so the cluster continues serving reads and writes even if a node or an entire region fails.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Globally distributed transactional applications$q$, $q$Enterprises run mission-critical banking, retail, or media applications that require strong consistency and continuous availability across multiple regions.$q$, $q$Enterprise engineering and infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$PostgreSQL migration for scale$q$, $q$Teams outgrowing single-node PostgreSQL migrate to CockroachDB to gain horizontal scalability while keeping existing drivers and query patterns.$q$, $q$Backend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Regulated, data-residency-sensitive workloads$q$, $q$Organizations use geo-partitioning to keep specific customer data within required jurisdictions while running a single logical database.$q$, $q$Compliance-focused enterprises in finance and healthcare$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Basic$q$, $q$Free (usage-based beyond free tier)$q$, $q$pay-as-you-go$q$, NULL, $q$["50M request units/month free","10 GiB storage free","Scales to zero","99.99% uptime","AWS/GCP multi-region"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Standard$q$, $q$From $0.18/hr (2 vCPUs)$q$, $q$hourly$q$, NULL, $q$["Provisioned compute","Instant scaling up to 200 vCPUs","On-demand storage","Private connectivity"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Advanced$q$, $q$From $0.60/hr (4 vCPUs)$q$, $q$hourly$q$, NULL, $q$["Unlimited scaling","AWS/GCP/Azure multi-region","Up to 99.999% uptime","CMEK encryption","HIPAA/PCI-DSS compliance"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$Self-Hosted$q$, $q$Free under $10M revenue; per-CPU-core fee above$q$, $q$annual/custom$q$, NULL, $q$["Full enterprise feature set","Run on your own infrastructure","Source-available license"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CockroachDB is a distributed SQL database built by Cockroach Labs, founded in 2015 by former Google engineers Spencer Kimball, Peter Mattis, and Ben Darnell, who previously worked on Google's Spanner distributed database. It is designed to survive node, data center, and even regional failures while maintaining strong consistency and PostgreSQL wire compatibility.$q$, $q$Headquartered in New York City, Cockroach Labs has raised over $800 million across nine funding rounds, including a $278 million Series F led by Greenoaks that valued the company at approximately $5 billion.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CockroachDB automatically shards, replicates, and rebalances data using the Raft consensus protocol, enabling multi-active availability that keeps a cluster serving reads and writes even during regional outages. Geo-partitioning lets specific data be pinned to specific regions for data residency and latency requirements.$q$, $q$Recent additions include AI-oriented capabilities such as an MCP server, a ccloud CLI, agent skills, and distributed vector indexing, reflecting growing demand for databases that natively support AI agent and RAG workloads.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CockroachDB Cloud offers three tiers: Basic (pay-as-you-go, starting free with 50M request units and 10 GiB storage monthly), Standard (provisioned compute starting at $0.18/hour for 2 vCPUs), and Advanced (starting at $0.60/hour for 4 vCPUs, with unlimited scaling and compliance features like CMEK and HIPAA/PCI-DSS support).$q$, $q$Self-hosted CockroachDB is source-available; since an August 2024 licensing change, companies with more than $10 million in annual revenue must pay a per-CPU-core fee to self-host, while smaller companies and startups below that threshold can use the same enterprise-grade version free of charge.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b91ae4a4-138d-4d64-ad9d-e248ca4f5aaa', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
